module counter(clk, reset, count);  
    input clk;  
    input reset;  
    output reg [1:0] count;  
  wire _tap_clk = clk & {1{1'b1}};


    always @(posedge clk or posedge reset) begin  
        if (reset)  
            count <= 2'b00;  
        else  
            count <= count + 1;  
    end  
endmodule
